const rows = $input.all();
if (rows.length === 0) {
  return []; // No active, non-muted developers — exit gracefully
}
const developers = rows.map(r => ({
  discord_id:        r.json.discord_id,
  name:              r.json.name,
  clockify_user_id:  r.json.clockify_user_id  || null,
  calendar_email:    r.json.calendar_email    || null,
  heard_from_today:  r.json.heard_from_today  === true || r.json.heard_from_today  === 'true',
  already_contacted: r.json.already_contacted === true || r.json.already_contacted === 'true'
}));
return [{ json: { developers } }];

// H-02: reduce Clockify response to userId-only before n8n logs the payload.
// Discards all other fields (name, email, dates) that could expose non-roster workspace members.
const raw = $json;
const ids = [];
let ok = false;
try {
  if (Array.isArray(raw)) {
    ok = true;
    for (const r of raw) {
      if (r.userId) ids.push(String(r.userId));
    }
  }
} catch (_) {}
return [{ json: { clockify_ok: ok, clockify_off_ids: ids } }];

const developers = $('Aggregate & Guard Empty').first().json.developers;

// --- Clockify primary source (pre-stripped to userId-only by Strip Clockify Fields) ---
const clockifyData = $('Strip Clockify Fields').first().json;
const clockifyOk = clockifyData.clockify_ok;
const clockifyUnavailable = new Set(clockifyData.clockify_off_ids);

// --- Google Calendar secondary source (OOO = busy 6+ hours) ---
// SC-06a: stricter source wins — if Calendar marks OOO, treat as not scheduled
const calRaw = $('Check Google Calendar OOO').first()?.json;
const calUnavailableEmails = new Set();
let calOk = false;
try {
  if (calRaw && typeof calRaw.calendars === 'object') {
    calOk = true;
    for (const [email, data] of Object.entries(calRaw.calendars)) {
      if (Array.isArray(data.busy)) {
        const isOOO = data.busy.some(p => {
          const hours = (new Date(p.end) - new Date(p.start)) / 3_600_000;
          return hours >= 6;
        });
        if (isOOO) calUnavailableEmails.add(email.toLowerCase());
      }
    }
  }
} catch (_) {}

// SC-18: both sources unavailable → fail-safe, no contacts, log for TL visibility
if (!clockifyOk && !calOk) {
  return [{ json: { missing_developers: [], sc18_failsafe: true } }];
}

// Build check-in list — SC-04/SC-05: no productivity reasoning; only schedule + heard-from
const missing = [];
for (const dev of developers) {
  // Already heard from today (standup received)
  if (dev.heard_from_today) continue;
  // Already contacted today — DB UNIQUE guard also covers this at insert time
  if (dev.already_contacted) continue;

  // SC-06a: if either available source marks person as unavailable, skip them
  let scheduled = true;
  if (clockifyOk && dev.clockify_user_id) {
    if (clockifyUnavailable.has(String(dev.clockify_user_id))) scheduled = false;
  }
  if (calOk && dev.calendar_email) {
    if (calUnavailableEmails.has(dev.calendar_email.toLowerCase())) scheduled = false;
  }
  if (!scheduled) continue;

  // H-01: only discord_id forwarded — name excluded from execution logs
  missing.push({ discord_id: dev.discord_id });
}

return [{ json: { missing_developers: missing, sc18_failsafe: false } }];

// H-01: only discord_id forwarded — name was excluded from missing_developers
const { missing_developers } = $input.first().json;
return missing_developers.map(dev => ({ json: { discord_id: dev.discord_id } }));

// M-02: explicitly forward discord_id with the send result so Log Outreach reads from
// $json.discord_id (immediate upstream) rather than a distant item-paired node reference.
const discordId = $('Split Into DM Items').item.json.discord_id;
const messageId = $json.id || null;  // Discord message ID on success; null on DM failure
return [{ json: { discord_id: discordId, message_id: messageId, dm_sent: !!messageId } }];
